import React from "react";
import { Route } from "@/types/route";

interface Props {
  route: Route;
}

const RouteStatsBanner: React.FC<Props> = ({ route }) => {
  const totalStops = route.stops.length;
  const busCount = route.busLocations?.length ?? 0;

  const avgDelay =
    route.delayPredictions && route.delayPredictions.length
      ? Math.round(
          route.delayPredictions.reduce(
            (sum, p) => sum + p.predictedDelayMinutes,
            0
          ) / route.delayPredictions.length
        )
      : 0;

  return (
    <div className="info-banner-route">
      <div className="banner-item">
        <div className="banner-label">Total Stops</div>
        <div className="banner-value">{totalStops}</div>
      </div>

      <div className="banner-item">
        <div className="banner-label">Buses</div>
        <div className="banner-value">{busCount}</div>
      </div>

      <div className="banner-item">
        <div className="banner-label">Avg. Delay</div>
        <div className="banner-value" style={{ color: "#ffc107" }}>
          +{avgDelay} min
        </div>
      </div>
    </div>
  );
};

export default RouteStatsBanner;
